const webhookData = $('Webhook Trigger').first().json;
const body = webhookData.body || webhookData;
const runRow = $('Start Scrape Run').first().json;
const runId = Array.isArray(runRow) ? (runRow[0] && runRow[0].id) : (runRow && runRow.id);

const defaults = { queries: [], query: '', lat: null, lng: null, zoom: 12, countryCode: 'us', language: 'en', resultsPerQuery: 20 };
const params = Object.assign({}, defaults);
for (const k in defaults) { if (body[k] !== undefined && body[k] !== null && body[k] !== '') params[k] = body[k]; }

let queries = [];
if (Array.isArray(params.queries) && params.queries.length > 0) {
  queries = params.queries.filter(q => typeof q === 'string' && q.trim()).map(q => q.trim());
} else if (typeof params.query === 'string' && params.query.trim()) {
  queries = [params.query.trim()];
}

const errors = [];
if (queries.length === 0) errors.push('queries (array) or query (string) is required');
if (params.lat === null || isNaN(Number(params.lat))) errors.push('lat must be a number');
if (params.lng === null || isNaN(Number(params.lng))) errors.push('lng must be a number');
if (errors.length > 0) throw new Error('Validation failed: ' + errors.join(', '));

return queries.map(q => ({ json: { query: q, lat: Number(params.lat), lng: Number(params.lng), zoom: Number(params.zoom) || 12, countryCode: String(params.countryCode || 'us').toLowerCase(), language: String(params.language || 'en').toLowerCase(), resultsPerQuery: Math.min(Math.max(Number(params.resultsPerQuery) || 20, 1), 100), runId: runId || null } }));

const allInputs = $input.all();
const seenPlaceIds = new Set();
const results = [];

function parseAddress(addr) {
  if (!addr) return { city: '', state: '', zip: '' };
  const parts = addr.split(',').map(s => s.trim());
  const lastPart = parts[parts.length - 1] || '';
  const usMatch = lastPart.match(/^([A-Z]{2})\s+(\d{5})$/);
  if (usMatch) return { city: parts.length >= 2 ? parts[parts.length - 2] : '', state: usMatch[1], zip: usMatch[2] };
  const inMatch = lastPart.match(/^(.+?)\s+(\d{6})$/);
  if (inMatch) return { city: parts.length >= 2 ? parts[parts.length - 2] : inMatch[1], state: inMatch[1].length < 30 ? inMatch[1] : '', zip: inMatch[2] };
  return { city: parts.length >= 2 ? parts[parts.length - 2] : (parts[0] || ''), state: '', zip: '' };
}

for (const item of allInputs) {
  const places = (item.json && item.json.local_results) || [];
  for (const place of places) {
    if (!place.title) continue;
    const pid = place.place_id || place.data_id || '';
    if (pid && seenPlaceIds.has(pid)) continue;
    if (pid) seenPlaceIds.add(pid);
    const { city, state, zip } = parseAddress(place.address);
    const lat = place.gps_coordinates ? place.gps_coordinates.latitude : null;
    const lng = place.gps_coordinates ? place.gps_coordinates.longitude : null;
    results.push({ json: {
      place_id: pid,
      business_name: place.title || '',
      category: place.type || (Array.isArray(place.types) ? place.types[0] : '') || '',
      full_address: place.address || '',
      city, state, zip,
      phone: place.phone || '',
      website: place.website || '',
      google_rating: place.rating || null,
      review_count: place.reviews || 0,
      maps_description: place.description || '',
      opening_hours: place.hours || '',
      google_maps_url: pid ? ('https://www.google.com/maps/place/?q=place_id:' + pid) : '',
      latitude: lat, longitude: lng,
      source_query: item.json.query,
      source_lat: item.json.lat,
      source_lng: item.json.lng,
      source_country_code: item.json.countryCode,
      source_language: item.json.language
    }});
  }
}

return results;

const allItems = $input.all();
const leads = allItems.map(i => i.json);
const runId = $('Validate Input').first() ? $('Validate Input').first().json.runId : null;
return [{ json: { leads, count: leads.length, runId } }];

const agg = $('Aggregate Leads').first().json;
const validated = $('Validate Input').all();
return [{ json: { success: true, queriesRun: validated.length, queries: validated.map(v => v.json.query), leadsFound: agg.count, runId: agg.runId, countryCode: validated[0] ? validated[0].json.countryCode : null, timestamp: new Date().toISOString() } }];

